import React, { useState } from "react";
import { useFormik } from "formik";
import * as yup from "yup";
import { useDispatch, useSelector } from "react-redux";
import { useNavigate } from "react-router-dom";
import CustomInput from "../../components/CustomInput";
import { forgotPassword } from "../../features/ForgotPassword/ForgotPasswordSlice"; // assuming you have this action

let schema = yup.object().shape({
  email: yup
    .string()
    .email("Email should be valid")
    .required("Email is Required"),
});

const ForgotPassword = () => {
  const [message, setMessage] = useState("");
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const formik = useFormik({
    initialValues: {
      email: "",
    },
    validationSchema: schema,
    onSubmit: (values) => {
      // Dispatch the action to send the reset password email link
      dispatch(forgotPassword(values.email))
        .then(() => {
          setMessage("Password reset link sent to your email!");
          setTimeout(() => navigate("/"), 3000); // Redirect after 3 seconds
        })
        .catch((error) => setMessage("Error sending reset link"));
    },
  });

  return (
    <div className="flex items-center justify-center min-h-screen bg-gray-100 py-5">
      <div className="bg-white rounded-lg shadow-lg p-6 w-full max-w-md mx-4 md:mx-auto">
        <h3 className="text-center text-2xl font-bold mb-4">Forgot Password</h3>
        <p className="text-center text-gray-600 mb-4">
          Enter your email to receive a password reset link.
        </p>
        {message && (
          <div className="text-center text-green-500 mb-4">{message}</div>
        )}
        <form onSubmit={formik.handleSubmit}>
          <CustomInput
            type="text"
            label="Email Address"
            id="email"
            name="email"
            onChng={formik.handleChange("email")}
            onBlr={formik.handleBlur("email")}
            val={formik.values.email}
            className="mb-4"
          />
          {formik.touched.email && formik.errors.email && (
            <div className="text-red-500 text-sm mb-2">{formik.errors.email}</div>
          )}
          <button
            className="w-full bg-yellow-500 text-white font-bold py-2 px-4 rounded hover:bg-yellow-600 focus:outline-none focus:shadow-outline"
            type="submit"
          >
            Send Reset Link
          </button>
        </form>
      </div>
    </div>
  );
};

export default ForgotPassword;
